        tune: "LONDON NEW",
        meter: "C.M. (8.6.8.6)",
        key: "E♭ Major",
        scripture: "Emi o gbé oju mi si ori oke wọnnì, nibo ni iranlọwọ mi yio ti nwa? - Orin Dafidi 121:1",
        theme: "Isin",
        year: 1707,
