        tune: "SANDON",
        meter: "10s. 4s",
        key: "Eb Major",
        scripture: "Ní ọ̀sán ni ó fi àwọsánmọ̀ darí wọn, àti ní gbogbo òru pẹ̀lú ìmọ́lẹ̀ iná. - Orin Dafidi 78:14",
        theme: "Isin Ale",
