      "YBH101": {
        title: "JÍ, ìwọ Kristian, kí o kí òrọ ayọ̀",
        number: "YBH101",
        author: "Unknown",
        composer: "Unknown",
        tune: "YORKSHIRE",
        meter: "6. 10s",
        key: "F Major",
        scripture: "Àngẹ́lì náà sì wí fún wọn pé, Má bẹ̀rù: sá wò ó, mo mú ìhìnrere ayọ̀ ńlá fún nyín wá, tí yíò ṣe ti ènìyàn gbogbo. - Luku 2:10",
        theme: "Ibi Kristi",
        year: "Traditional",
        verses: [
          {
            number: "1",
            musicSigns: ["f", "x", "x", "x", "x", "x"],
            lines: [
              "JÍ, ìwọ Kristian, kí o kí òrọ ayọ̀",
              "Tí a bí Olùgbàlà aráyé;",
              "Dìde, kí o kọrin ìfẹ́ Ọlọ́run,",
              "Tí àwọn Àngẹ́lì ńkọ ní ọjọ́ kìíní,",
              "Láti ọ̀dọ̀ wọn ní ìhìn náà ti bẹ̀rẹ̀;",
              "Ìhìn Ọmọ Ọlọ́run tí a bí sí ayé."
            ]
          },
          {
            number: "2",
            musicSigns: ["mf", "x", "x", "x", "x", "x"],
            lines: [
              "Ìgbànà là ràn akéde Àngẹ́lì,",
              "Tí ó sọ fún àwọn Olùṣọ́-àgùtàn, pé,",
              "\"Mo mú ìhìn rere Olùgbàlà wá,",
              "Tí a bí fún nyín àti gbogbo ayé.\"",
              "Ọlọ́run mú ìlérí Rẹ̀ ṣe lónìí,",
              "A bí Olùgbàlà, Kristi Olúwa."
            ]
          },
          {
            number: "3",
            musicSigns: ["mf", "x", "x", "x", "x", "x"],
            lines: [
              "Bí akéde Àngẹ́lì náà ti sọ tán,",
              "Ọ̀pọ̀lọpọ̀ ogun ọ̀run sì dé;",
              "Nwọ́n ńkọrin ayọ̀ tí etí kò gbọ́ rí,",
              "Ọ̀run sì hó fún ìyìn Ọlọ́run pé,",
              "\"Ògo ni fún Ọlọ́run lóke ọ̀run",
              "Àlàáfíà àti ìfẹ́ sí ènìyàn.\""
            ]
          },
          {
            number: "4",
            musicSigns: ["mf", "x", "x", "x", "x", "x"],
            lines: [
              "Ó yẹ kí àwa kí ó má rò lọ́kàn wa,",
              "Ìfẹ́ ńlá tí Ọlọ́run ní sí ọkàn wa,",
              "Kí a sì rò tí ọmọ náà tí a bí lónìí,",
              "Tí ó wá jìyà òro agbélébù.",
              "Kí àwa sì tẹ̀lé lí àna Rẹ̀,",
              "Títí a ó fi dé ìbùgbé lóke."
            ]
          },
          {
            number: "5",
            musicSigns: ["f", "x", "x", "x", "x", "x"],
            lines: [
              "Nígbà náà ìgbà bá dé ọ̀run lọ́hùn,",
              "A ó kọrin ayọ̀ tí ìràpadà;",
              "Ògo Ẹni tí a bí fún wa lónìí,",
              "Yíò má ràn yí wa ká títí láìláì;",
              "A ó má kọrin ìfẹ́ Rẹ̀ títí,",
              "Ọba Àngẹ́lì, Ọba ènìyàn."
            ]
          }
        ],
        history: "Orin àtọwọ́dọ́wọ́ Yorùbá tí ó dá lórí Luku 2:10. Ó ń sọ nípa ìbí Kristi àti ayọ̀ tí ó mú wá fún gbogbo aráyé. Orin yìí ń kọ́ wa láti jí, yọ̀, àti kọrin ìfẹ́ Ọlọ́run."
      },

