      "YBH444": {
        title: "LÁT’ òkè tútù Grinland",
        number: "YBH444",
        author: "Reginald Heber",
        composer: "Unknown",
        tune: "Unknown",
        meter: "Unknown",
        key: "Unknown",
        scripture: "Unknown",
        theme: "Ihinrere",
        year: "1819",
        musicSigns: [],
        verses: [
          {
            number: 1,
            musicSigns: ["x", "x", "x", "x", "x", "x", "x", "x"],
            lines: [
              "LÁT’ òkè tútù Grinland,",
              "Láti òkun India,",
              "Níb’ odò ọ̀run Áfrík’,",
              "Ńsan ‘yànrìn wúrà wọn;",
              "Lát’ ọ̀pọ̀ odò ‘gbàní,",
              "Láti igbó ọ̀pẹ,",
              "A ńlọ kí a lè gbà wọ́n,",
              "Kúrò n’nú sínà wọn."
            ]
          },
          {
            number: 2,
            musicSigns: ["x", "x", "x", "x", "x", "x", "x", "x"],
            lines: [
              "Afẹ́fẹ́ ọ̀run dídùn,",
              "Ńfẹ́ jẹ́jẹ́ ní Seilon;",
              "Bí ohun t’ a ńrí dára,",
              "Ènìyàn l’ ó burú;",
              "Lásán lásán l’ Ọlọ́run",
              "Ńt’ ẹ̀bùn Rẹ̀ gbogbo ká,",
              "Kèfèrí, n’nú ‘fójú wọn,",
              "Ńwólẹ̀ bọ òkúta."
            ]
          },
          {
            number: 3,
            musicSigns: ["x", "x", "x", "x", "x", "x", "x", "x"],
            lines: [
              "Ǹjẹ́ àwa tí a mọ̀ye",
              "Nípa ọgbọ́n ọ̀run,",
              "Ó tọ́ k’ a f’ ìmọ́lẹ̀ dù",
              "Àwọn t’ ó wà l’ ókun?",
              "Ìgbàlà, à, ìgbàlà!",
              "Fúnrere ayọ̀ náà",
              "Títí gbogbo orílẹ̀",
              "Yíò mọ̀ Mèsáyà."
            ]
          },
          {
            number: 4,
            musicSigns: ["x", "x", "x", "x", "x", "x", "x", "x"],
            lines: [
              "Ẹ̀fúùfù, mú ‘hìn rẹ̀ lọ,",
              "Àti ẹ̀yin odò;",
              "Títí, bí òkun ògo",
              "Yíò tan yí ayé ká;",
              "Tít’ Ọ̀d’àgùtàn t’ a pa",
              "Fún ìràpadà wa",
              "Yíò padà wá jọba",
              "L’ àlàáfíà láéláé."
            ]
          }
        ],
        history: "Traditional Yoruba hymn."
      },
      "YBH445": {
        title: "GBỌ́ ohùn Jésù tí ńké pe",
        number: "YBH445",
        author: "Unknown",
        composer: "Unknown",
        tune: "Unknown",
        meter: "Unknown",
        key: "Unknown",
        scripture: "Unknown",
        theme: "Ihinrere",
        year: "Traditional",
        musicSigns: [],
        verses: [
          {
            number: 1,
            musicSigns: ["x", "x", "x", "x", "x", "x", "x", "x"],
            lines: [
              "GBỌ́ ohùn Jésù tí ńké pe,",
              "Ta ni yíò ṣiṣẹ́ lónìí?",
              "Oko pọ́n púpọ̀ ṣiṣẹ́ lónìí?",
              "Ta ni yíò lọ ká a?",
              "Kíkankíkan l’ Olúwa ńpe,",
              "Ẹ̀bùn ńlá l’ O fi fún ọ,",
              "Ta ni yíò f’ ayọ̀ dáhùn pé,",
              "“Ẹ̀mí nìyí; rán mi, rán mi.”"
            ]
          },
          {
            number: 2,
            musicSigns: ["x", "x", "x", "x", "x", "x", "x", "x"],
            lines: [
              "B’ ìwọ kò lè la òkun lọ,",
              "Láti wá ‘wọn kèfèrí,",
              "O lè rí wọn nítòsí rẹ,",
              "Wọ́n wà l’ ẹnu-ọnà rẹ;",
              "B’ o kò lè fi wúrà tọrẹ,",
              "O lè fi bàbà ọrẹ,",
              "Diẹ̀ t’ o sì ṣe fún Jésù,",
              "‘Yebíye ni l’ ojú Rẹ̀."
            ]
          },
          {
            number: 3,
            musicSigns: ["x", "x", "x", "x", "x", "x", "x", "x"],
            lines: [
              "B’ o kò lè s’ ọ̀rọ̀ b’ ángẹ́lì,",
              "B’ o kò lè wàásù bí Pọ́ọ̀lù,",
              "Ìwọ lè sọ t’ ìfẹ́ Jésù,",
              "Ìwọ lè sọ ti ikú Rẹ̀;",
              "B’ ìwọ kò lè jí ẹlẹ́ṣẹ̀",
              "Nínú ewu ìdájọ́,",
              "‘Wọ lè kọ́ àwọn ọmọdé",
              "Li ọ̀nà t’ Olùgbàlà."
            ]
          },
          {
            number: 4,
            musicSigns: ["x", "x", "x", "x", "x", "x", "x", "x"],
            lines: [
              "B’ ìwọ kò lè k’ àgbàlagbà,",
              "Kríst’ Olùṣ’àgùtàn ni,",
              "“Bọ́ àwọn ọ̀d’-àgùtàn Mi,",
              "Gbé oúnjẹ tí wọn lọ́dọ̀:”",
              "O lè jẹ́ pé àwọn ‘mọdé",
              "T’ o ti fi ọwọ́ rẹ tọ́,",
              "Ni yíò wà láàrin ọ̀ṣọ́ rẹ",
              "Gbàt’ o bá dé ‘lé rere."
            ]
          },
          {
            number: 5,
            musicSigns: ["x", "x", "x", "x", "x", "x", "x", "x"],
            lines: [
              "Má jẹ́k’ ènìyàn gbọ́ wípé,",
              "“Kò sí ǹkan t’ èmi lè ṣe,”",
              "Nígbàt’ àwọn kèfèrí ńkú,",
              "Tí Olúwa sì ńpe ọ,",
              "F’ ayọ̀ gba iṣẹ́ t’ O rán ọ,",
              "K’ iṣẹ́ Rẹ̀ jẹ́ ayọ̀ rẹ;",
              "F’ ayọ̀ dáhùn gbàt’ O pè ọ",
              "Pé, “Ẹ̀mí nìyí, rán mi.”"
            ]
          }
        ],
        history: "Traditional Yoruba hymn."
      },
